import{_ as n,c as t,o as a,a5 as o}from"./chunks/framework.CgT1UzWm.js";const h=JSON.parse('{"title":"Changelog v3.9.0 (2026-02-23)","description":"","frontmatter":{},"headers":[],"relativePath":"guide/changelog/v3.9.0.md","filePath":"guide/changelog/v3.9.0.md"}'),i={name:"guide/changelog/v3.9.0.md"};function s(r,e,c,d,l,p){return a(),t("div",null,e[0]||(e[0]=[o('<h1 id="changelog-v3-9-0-2026-02-23" tabindex="-1">Changelog v3.9.0 (2026-02-23) <a class="header-anchor" href="#changelog-v3-9-0-2026-02-23" aria-label="Permalink to &quot;Changelog v3.9.0 (2026-02-23)&quot;">​</a></h1><h2 id="version-3-9-0-2026-02-23" tabindex="-1">Version <a href="https://github.com/NpgsqlRest/NpgsqlRest/tree/3.9.0" target="_blank" rel="noreferrer">3.9.0</a> (2026-02-23) <a class="header-anchor" href="#version-3-9-0-2026-02-23" aria-label="Permalink to &quot;Version [3.9.0](https://github.com/NpgsqlRest/NpgsqlRest/tree/3.9.0) (2026-02-23)&quot;">​</a></h2><p><a href="https://github.com/NpgsqlRest/NpgsqlRest/compare/3.8.0...3.9.0" target="_blank" rel="noreferrer">Full Changelog</a></p><h3 id="commented-configuration-output-config" tabindex="-1">Commented Configuration Output (<code>--config</code>) <a class="header-anchor" href="#commented-configuration-output-config" aria-label="Permalink to &quot;Commented Configuration Output (`--config`)&quot;">​</a></h3><p>The <code>--config</code> output now includes inline JSONC comments with descriptions for every setting, matching the <code>appsettings.json</code> file exactly. This makes it easy to understand what each setting does without consulting the documentation. The default configuration file can be constructed with:</p><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npgsqlrest --config &gt; appsettings.json</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></details><h3 id="configuration-search-and-filter-config-filter" tabindex="-1">Configuration Search and Filter (<code>--config [filter]</code>) <a class="header-anchor" href="#configuration-search-and-filter-config-filter" aria-label="Permalink to &quot;Configuration Search and Filter (`--config [filter]`)&quot;">​</a></h3><p>Added an optional filter argument to <code>--config</code> that searches keys, comments, and values (case-insensitive) and returns only matching settings as valid JSONC:</p><details class="code-collapsible" open><summary>code</summary><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>npgsqlrest --config cors</span></span>\n<span class="line"><span>npgsqlrest --config=timeout</span></span>\n<span class="line"><span>npgsqlrest --config minworker</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div></details><p>Output preserves the full section hierarchy so it can be copy-pasted directly into <code>appsettings.json</code>. When a key inside a section matches, the parent section wrapper is included. When a section name or its comment matches, the entire section is shown. Matched terms are highlighted with inverted colors in the terminal; piped output is plain text.</p><h3 id="cli-improvements" tabindex="-1">CLI Improvements <a class="header-anchor" href="#cli-improvements" aria-label="Permalink to &quot;CLI Improvements&quot;">​</a></h3><ul><li><strong>Case-insensitive config overrides</strong>: Command-line config overrides like <code>--Applicationname=test</code> now correctly update the existing <code>ApplicationName</code> key instead of creating a duplicate entry with different casing.</li><li><strong>Config validation on <code>--config</code></strong>: The <code>--config</code> command now validates configuration keys before dumping. Unknown keys (e.g., <code>--xxx=test</code>) produce an error on stderr and exit with code 1.</li><li><strong>Redirected output fix</strong>: Formatted CLI output (<code>--help</code>, <code>--version</code>) no longer crashes when stdout is redirected (e.g., piped or captured by a parent process).</li><li><strong>CLI test suite</strong>: Added process-based tests for all CLI commands (<code>--help</code>, <code>--version</code>, <code>--hash</code>, <code>--basic_auth</code>, <code>--config-schema</code>, <code>--annotations</code>, <code>--config</code>, <code>--config [filter]</code>, invalid args).</li></ul><hr>',13)]))}const u=n(i,[["render",s]]);export{h as __pageData,u as default};
